def _adjust_palette_lightness(self, lightness_factor):
    if self.mode not in ("P", "PA"):
        raise ValueError("only 'P' or 'PA' images have a palette to adjust")

    mode = self.palette.mode
    bands = len(mode)
    color_bands = min(bands, 3)
    palette_bytes = bytearray(self.palette.palette)

    for i in range(0, len(palette_bytes), bands):
        for b in range(color_bands):
            value = round(palette_bytes[i + b] * lightness_factor)
            palette_bytes[i + b] = max(0, min(255, value))

    from . import ImagePalette

    self.palette = ImagePalette.ImagePalette(mode, bytes(palette_bytes))

